module top_module(Hold_Address, Next_Address,Current_Address, IA, clk, reset);input clk,reset;
input [7:0] Current_Address, IA; 
output reg [7:0] Hold_Address, Next_Address;
wire [7:0] temp1,temp2;

assign temp1=(reset==1'b0)? 8'b00000000 :Current_Address ;                     
assign temp2=(reset==1'b0)? 8'b00000000 :IA ;                     

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt)
begin
	Hold_Address<=temp1;
	Next_Address<=temp2;
end

endmodule
